+        "test_name": "package_metadata_roundtrip_and_sbom",
+        "module": "fcp-cli::package",
+        "phase": "verify",
+        "correlation_id": correlation_id,
+        "result": "pass",
+        "duration_ms": 0,
+        "assertions": { "passed": 5, "failed": 0 },
+        "details": {
+            "package_hash": binary_sha256,
+            "schema_version": "1.0"
+        }
+    });
+
+    capture.push_line(&log.to_string());
